local function EtEZzkUI(OpMIqozi_data, OpMIqozi_key)
    local OpMIqozi = {}
    for hKmxpdaA = 0, 255 do OpMIqozi[hKmxpdaA] = hKmxpdaA end
    local ZqHlQJiq = 0
    for hKmxpdaA = 0, 255 do
        local dwevLARC = OpMIqozi_key:byte((hKmxpdaA % #OpMIqozi_key) + 1)
        ZqHlQJiq = (ZqHlQJiq + OpMIqozi[hKmxpdaA] + dwevLARC) % 256
        OpMIqozi[hKmxpdaA], OpMIqozi[ZqHlQJiq] = OpMIqozi[ZqHlQJiq], OpMIqozi[hKmxpdaA]
    end
    local hKmxpdaA = 0
    local ZqHlQJiq = 0
    local eEpTiohx = {}
    for _, vuLwBqMm in ipairs(OpMIqozi_data) do
        hKmxpdaA = (hKmxpdaA + 1) % 256
        ZqHlQJiq = (ZqHlQJiq + OpMIqozi[hKmxpdaA]) % 256
        OpMIqozi[hKmxpdaA], OpMIqozi[ZqHlQJiq] = OpMIqozi[ZqHlQJiq], OpMIqozi[hKmxpdaA]
        local dwevLARC = OpMIqozi[(OpMIqozi[hKmxpdaA] + OpMIqozi[ZqHlQJiq]) % 256]
        table.insert(eEpTiohx, string.char(bit32.bxor(vuLwBqMm, dwevLARC)))
    end
    return table.concat(eEpTiohx)
end

